import { cacheLife, cacheTag, revalidateTag } from "next/cache";

import {
  isProductSyncRunning,
  readProductsFromSource,
  syncProductsFromUpstream,
} from "@/lib/db";

export async function getCatalogSnapshot() {
  "use cache";

  cacheLife("minutes");
  cacheTag("products");

  const snapshot = await readProductsFromSource();

  return {
    ...snapshot,
    productCount: snapshot.products.length,
  };
}

export function getCatalogSyncStatus() {
  return {
    isRunning: isProductSyncRunning(),
  };
}

export async function refreshCatalogInBackground() {
  await syncProductsFromUpstream();
  revalidateTag("products", "max");
}

import { after } from "next/server";

import {
  getCatalogSnapshot,
  getCatalogSyncStatus,
  refreshCatalogInBackground,
} from "@/lib/catalog";

export const dynamic = "force-dynamic";

function formatCurrency(amount: number) {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD",
    maximumFractionDigits: 0,
  }).format(amount);
}

function formatDateTime(value: string) {
  return new Intl.DateTimeFormat("en-US", {
    dateStyle: "medium",
    timeStyle: "short",
    timeZone: "UTC",
  }).format(new Date(value));
}

export default async function Page() {
  const [{ products, productCount, lastSyncedAt }, { isRunning }] =
    await Promise.all([getCatalogSnapshot(), getCatalogSyncStatus()]);

  return (
    <main style={styles.page}>
      <section style={styles.header}>
        <div>
          <p style={styles.eyebrow}>Admin</p>
          <h1 style={styles.title}>Product catalog</h1>
          <p style={styles.subtitle}>
            Browse the cached catalog quickly and trigger an ERP/PIM refresh
            without blocking day-to-day work.
          </p>
        </div>

        <form
          action={async () => {
            "use server";

            after(async () => {
              await refreshCatalogInBackground();
            });
          }}
        >
          <button style={styles.button} type="submit">
            Sync latest catalog
          </button>
        </form>
      </section>

      <section style={styles.metaGrid}>
        <div style={styles.metaCard}>
          <span style={styles.metaLabel}>Products</span>
          <strong style={styles.metaValue}>{productCount}</strong>
        </div>
        <div style={styles.metaCard}>
          <span style={styles.metaLabel}>Last synced</span>
          <strong style={styles.metaValue}>{formatDateTime(lastSyncedAt)}</strong>
        </div>
        <div style={styles.metaCard}>
          <span style={styles.metaLabel}>Sync status</span>
          <strong style={styles.metaValue}>
            {isRunning ? "Refresh running" : "Idle"}
          </strong>
        </div>
      </section>

      <p style={styles.notice}>
        Sync requests run in the background. Cached catalog data tagged as
        <code style={styles.code}>products</code> stays fast to browse and is
        marked stale after the sync completes so dependent views converge
        shortly after.
      </p>

      <div style={styles.tableWrap}>
        <table style={styles.table}>
          <thead>
            <tr>
              <th style={styles.th}>SKU</th>
              <th style={styles.th}>Product</th>
              <th style={styles.th}>Availability</th>
              <th style={styles.th}>Inventory</th>
              <th style={styles.th}>Price</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.id} style={styles.row}>
                <td style={styles.tdMono}>{product.sku}</td>
                <td style={styles.td}>{product.name}</td>
                <td style={styles.td}>{product.availability}</td>
                <td style={styles.td}>{product.inventory}</td>
                <td style={styles.td}>{formatCurrency(product.price)}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </main>
  );
}

